#@category Imperialism
# Export USER_DEFINED function decompilation output into split .cpp files.
#
# Supported runtime:
# - Ghidra 12.0.2 PUBLIC only
#
# Output layout:
# - arg[0] or directory chooser target
# - one generated .cpp per namespace bucket
# - _manifest.json tracks generated files for stale cleanup
# - index.csv maps address/name/prototype to generated file
#
# Notes:
# - Files are overwritten on each export for deterministic rename propagation.
# - These files are intended as a maintained reference snapshot, not build-ready code.

import json
import os
import re

from ghidra.app.decompiler import DecompInterface
from ghidra.framework import Application
from ghidra.program.model.symbol import SourceType

EXPECTED_GHIDRA_VERSION = "12.0.2"
EXPECTED_GHIDRA_RELEASE = "PUBLIC"

EXPORT_ONLY_USER_DEFINED = True
DECOMPILER_TIMEOUT_SECONDS = 30
DEFAULT_MAX_FUNCTIONS_PER_FILE = 250

MANIFEST_BASENAME = "_manifest.json"
INDEX_BASENAME = "index.csv"


def enforce_ghidra_version():
    actual_version = Application.getApplicationVersion()
    actual_release = Application.getApplicationReleaseName()
    if (
        actual_version != EXPECTED_GHIDRA_VERSION
        or actual_release != EXPECTED_GHIDRA_RELEASE
    ):
        raise RuntimeError(
            "Unsupported Ghidra runtime: {} {}. Expected {} {}.".format(
                actual_version,
                actual_release,
                EXPECTED_GHIDRA_VERSION,
                EXPECTED_GHIDRA_RELEASE,
            )
        )


def has_ws(s):
    return (" " in s) or ("\t" in s) or ("\r" in s) or ("\n" in s)


def clean_line(s):
    return " ".join(s.split())


def sanitize_path_component(name):
    value = re.sub(r"[^A-Za-z0-9._-]+", "_", name)
    value = re.sub(r"_+", "_", value).strip("._")
    if not value:
        return "unnamed"
    return value


def normalize_relpath(relpath):
    return relpath.replace("\\", "/")


def safe_join(base_dir, relpath):
    rel = normalize_relpath(relpath)
    parts = [p for p in rel.split("/") if p]
    if rel.startswith("/") or ".." in parts:
        raise RuntimeError("Unsafe relative path: {}".format(relpath))
    return os.path.join(base_dir, *parts)


def load_old_files(manifest_path):
    if not os.path.isfile(manifest_path):
        return []
    try:
        with open(manifest_path, "rb") as fd:
            payload = json.loads(fd.read().decode("utf-8"))
        return list(payload.get("generated_cpp_files", []))
    except Exception as exc:
        print("Warning: could not read previous manifest {}: {}".format(manifest_path, exc))
        return []


def remove_old_generated_files(base_dir, old_files):
    for rel in old_files:
        try:
            full = safe_join(base_dir, rel)
        except Exception:
            continue
        if os.path.isfile(full):
            os.remove(full)


def remove_empty_dirs(root_dir):
    for cur, dirs, files in os.walk(root_dir, topdown=False):
        if cur == root_dir:
            continue
        if dirs or files:
            # os.walk lists pre-delete entries; re-check from filesystem.
            if os.listdir(cur):
                continue
        os.rmdir(cur)


def namespace_parts(namespace):
    parts = []
    ns = namespace
    while ns is not None and not ns.isGlobal():
        n = ns.getName()
        if n and n != "Global":
            parts.append(n)
        ns = ns.getParentNamespace()
    parts.reverse()
    return parts


def namespace_to_relpath(parts):
    if not parts:
        return "global.cpp"
    safe = [sanitize_path_component(p) for p in parts]
    if len(safe) == 1:
        return safe[0] + ".cpp"
    return "/".join(safe[:-1] + [safe[-1] + ".cpp"])


def to_single_line_comment(value):
    if value is None:
        return ""
    return clean_line(str(value).replace("|", " "))


def relpath_with_part(relpath, part_idx):
    rel = normalize_relpath(relpath)
    parent = os.path.dirname(rel)
    name = os.path.basename(rel)
    if name.lower().endswith(".cpp"):
        stem = name[:-4]
    else:
        stem = name
    part_name = "{}_part{:03d}.cpp".format(stem, part_idx)
    if parent:
        return normalize_relpath(parent + "/" + part_name)
    return part_name


def split_bucket(relpath, entries, max_functions_per_file):
    if max_functions_per_file <= 0 or len(entries) <= max_functions_per_file:
        return [(relpath, entries)]

    chunks = []
    idx = 1
    for off in range(0, len(entries), max_functions_per_file):
        chunk_entries = entries[off : off + max_functions_per_file]
        chunks.append((relpath_with_part(relpath, idx), chunk_entries))
        idx += 1
    return chunks


def build_file_text(module_name, program_name, relpath, entries):
    out = []
    out.append("// AUTOGENERATED FROM GHIDRA. DO NOT EDIT.\n")
    out.append("// Script: ExportDecompiledBodies_Split.py\n")
    out.append("// Program: {}\n".format(program_name))
    out.append("// Bucket: {}\n\n".format(relpath))

    for entry in entries:
        out.append("// FUNCTION: {} 0x{:08X}\n".format(module_name, entry["address"]))
        out.append("// GHIDRA_NAME: {}\n".format(entry["name"]))
        out.append("// GHIDRA_PROTO: {}\n".format(entry["prototype"]))
        if entry["ok"]:
            out.append(entry["c"].rstrip())
            out.append("\n\n")
        else:
            out.append("/* DECOMPILATION FAILED: {} */\n\n".format(entry["error"]))
    return "".join(out)


def write_bytes(path, data):
    parent = os.path.dirname(path)
    if parent and not os.path.isdir(parent):
        os.makedirs(parent)
    with open(path, "wb") as fd:
        fd.write(data)


enforce_ghidra_version()

args = getScriptArgs()
if args is not None and len(args) >= 1 and args[0]:
    out_dir = args[0]
else:
    out_dir = askDirectory("Export decompiled bodies directory...", "Select").absolutePath

if args is not None and len(args) >= 2 and args[1]:
    max_functions_per_file = int(args[1])
else:
    max_functions_per_file = DEFAULT_MAX_FUNCTIONS_PER_FILE

out_dir = os.path.abspath(out_dir)
if not os.path.isdir(out_dir):
    os.makedirs(out_dir)

module_name = os.path.splitext(currentProgram.getName())[0].upper()
program_name = currentProgram.getName()

manifest_path = os.path.join(out_dir, MANIFEST_BASENAME)
index_path = os.path.join(out_dir, INDEX_BASENAME)

old_files = load_old_files(manifest_path)
remove_old_generated_files(out_dir, old_files)

decomp = DecompInterface()
decomp.toggleCCode(True)
decomp.toggleSyntaxTree(False)
decomp.setSimplificationStyle("decompile")
decomp.openProgram(currentProgram)

bucket_map = {}
index_rows = ["address|name|prototype|file|status"]
count_total = 0
count_fail = 0
count_skipped_nonuser = 0
count_skipped_ws = 0

fm = currentProgram.getFunctionManager()
it = fm.getFunctions(True)
while it.hasNext() and not monitor.isCancelled():
    func = it.next()
    sym = func.getSymbol()
    if sym is None:
        continue
    if EXPORT_ONLY_USER_DEFINED and sym.getSource() != SourceType.USER_DEFINED:
        count_skipped_nonuser += 1
        continue

    name = func.getName(True)
    if has_ws(name):
        count_skipped_ws += 1
        print("Skipping function (whitespace in name): {}".format(name))
        continue

    relpath = namespace_to_relpath(namespace_parts(func.getParentNamespace()))
    addr = func.getEntryPoint().getOffset()
    proto = to_single_line_comment(func.getPrototypeString(True, True))

    res = decomp.decompileFunction(func, DECOMPILER_TIMEOUT_SECONDS, monitor)
    decomp_c = None
    error = ""
    ok = False
    if res is not None and res.decompileCompleted():
        decomp_func = res.getDecompiledFunction()
        if decomp_func is not None:
            decomp_c = decomp_func.getC()
            ok = decomp_c is not None
    if not ok:
        count_fail += 1
        if res is not None:
            error = to_single_line_comment(res.getErrorMessage())
        if not error:
            error = "unknown decompiler failure"
        decomp_c = ""

    entry = {
        "address": addr,
        "name": to_single_line_comment(name),
        "prototype": proto,
        "ok": ok,
        "c": decomp_c,
        "error": error,
    }
    bucket_map.setdefault(relpath, []).append(entry)
    count_total += 1

generated_files = []
for relpath in sorted(bucket_map.keys()):
    entries = bucket_map[relpath]
    entries.sort(key=lambda e: e["address"])
    split_files = split_bucket(relpath, entries, max_functions_per_file)
    for out_relpath, chunk_entries in split_files:
        text = build_file_text(module_name, program_name, out_relpath, chunk_entries)
        full_path = safe_join(out_dir, out_relpath)
        write_bytes(full_path, text.encode("utf-8"))
        generated_files.append(normalize_relpath(out_relpath))
        for entry in chunk_entries:
            status = "ok" if entry["ok"] else "failed"
            index_rows.append(
                "{:x}|{}|{}|{}|{}".format(
                    entry["address"],
                    entry["name"],
                    entry["prototype"],
                    out_relpath,
                    status,
                )
            )

write_bytes(index_path, ("\n".join(index_rows) + "\n").encode("utf-8"))

manifest_payload = {
    "generated_cpp_files": generated_files,
    "program": program_name,
    "module": module_name,
    "function_count": count_total,
    "failed_count": count_fail,
}
write_bytes(
    manifest_path,
    (json.dumps(manifest_payload, indent=2, sort_keys=True) + "\n").encode("utf-8"),
)

remove_empty_dirs(out_dir)

print("Wrote {} files under {}".format(len(generated_files), out_dir))
print("Functions exported: {}".format(count_total))
print("Decompiler failures: {}".format(count_fail))
print("Max functions per file: {}".format(max_functions_per_file))
print("Skipped non-user-defined: {}".format(count_skipped_nonuser))
print("Skipped whitespace names: {}".format(count_skipped_ws))
print("Index: {}".format(index_path))
print("Manifest: {}".format(manifest_path))
